import{_ as t,o as r,c as a,a7 as o}from"./chunks/framework.BgApuQ2e.js";const p="/images/7-3-billion-people-one-building/Rice.png",n="/images/7-3-billion-people-one-building/Carlos.png",l="/images/7-3-billion-people-one-building/Carlos-and-Others.png",i="/images/7-3-billion-people-one-building/Tower.png",s="/images/7-3-billion-people-one-building/3-Feet.png",h="/images/7-3-billion-people-one-building/Circle-1024x1024.jpg",m="/images/7-3-billion-people-one-building/china-tiananmen-square-aerial.jpg",g="/images/7-3-billion-people-one-building/scandinavia.png",b="/images/7-3-billion-people-one-building/Americans.png",f="/images/7-3-billion-people-one-building/All-Humans.png",w="/images/7-3-billion-people-one-building/Africa.jpg",u="/images/7-3-billion-people-one-building/NYC1.jpg",c="/images/7-3-billion-people-one-building/Crowd-1024x368.png",_="/images/7-3-billion-people-one-building/NYC2.jpg",d="/images/7-3-billion-people-one-building/108B.png",k="/images/7-3-billion-people-one-building/Cube1.jpg",y="/images/7-3-billion-people-one-building/Cube2.jpg",C="/images/7-3-billion-people-one-building/Cube3.jpg",B="/images/7-3-billion-people-one-building/MM1.png",j="/images/7-3-billion-people-one-building/pinit_fg_en_rect_gray_20.png",O=JSON.parse('{"title":"7.3 Billion People, One Building","description":"","frontmatter":{"title":"7.3 Billion People, One Building","titleZh":"73亿人 一栋楼装下","date":"2015-03-03T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html","slug":"7-3-billion-people-one-building"},"headers":[],"relativePath":"posts/7-3-billion-people-one-building.md","filePath":"posts/7-3-billion-people-one-building.md","lastUpdated":1782886257000}'),A={name:"posts/7-3-billion-people-one-building.md"};function q(P,e,v,M,T,x){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_73亿人-一栋楼装下-·-7-3-billion-people-one-building" tabindex="-1">73亿人 一栋楼装下 · 7.3 Billion People, One Building <a class="header-anchor" href="#_73亿人-一栋楼装下-·-7-3-billion-people-one-building" aria-label="Permalink to &quot;73亿人 一栋楼装下 · 7.3 Billion People, One Building&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html</a> · 2015-03-03</p></blockquote><p>写了一年半的 Wait But Why 之后,我发现了一个主题:人类这个话题好像老是冒出来。</p><p>有时我们聊人类是<a href="https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html" target="_blank" rel="noreferrer">从哪来的</a>,或者<a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">可能</a>要往哪去,或者我们彼此之间是怎么<a href="https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html" target="_blank" rel="noreferrer">联系</a>的;有时我们看看人类怎么<a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">互动</a><a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">、</a><a href="https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html" target="_blank" rel="noreferrer">交流</a>,以及<a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">建立</a><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">关系</a>。我们聊过<a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">有钱的</a>人类、<a href="https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html" target="_blank" rel="noreferrer">出名的</a>人类、<a href="https://waitbutwhy.com/2013/12/how-to-name-baby.html" target="_blank" rel="noreferrer">刚出生的</a>人类、<a href="https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html" target="_blank" rel="noreferrer">死掉的</a>人类,以及来自<a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">世界</a><a href="https://waitbutwhy.com/2014/07/russia-what-you-didnt-know.html" target="_blank" rel="noreferrer">各</a><a href="https://waitbutwhy.com/2014/07/japan-and-how-i-failed-to-figure-it-out.html" target="_blank" rel="noreferrer">个</a><a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">角</a><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">落</a><a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">的</a>人类。我们探讨过<a href="https://waitbutwhy.com/2014/12/what-makes-you-you.html" target="_blank" rel="noreferrer">做一个人</a>意味着什么,<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">做一个好人</a>意味着什么,以及我们是不是在宇宙里<a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer">孤零零的一群</a>。我们还花了大量时间去搞清楚,在这<a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">短短一生</a>里<a href="https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html" target="_blank" rel="noreferrer">到</a><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">底</a><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">什么</a><a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">最重要</a>。</p><p>但不知怎么的,聊了这么多,我们竟然从来没问过关于人类最最重要的那个问题——</p><p><em>得多大的一栋楼才能把所有人都塞进去?</em></p><p>这是个几千年来几乎没让任何人心痒过的问题,今天我们就来硬刚一下。</p><p>不过在我要求全部 73 亿人类停下手头的事、任我随意摆布挤成一团之前,咱们先聊聊 73 亿这个数字。</p><p>首先要说的是,当我在 2013 年 8 月发那篇关于<a href="https://waitbutwhy.com/2013/08/what-if-all-71-billion-people-moved-to.html" target="_blank" rel="noreferrer">人口密度</a>的文章时,反复提到的数字是 71 亿。从那时到现在,<a href="http://www.worldometers.info/world-population/" target="_blank" rel="noreferrer">世界人口</a>已经增长了 194,000,000,差不多 3%。</p><p>其次,73 亿人是一大堆人。如果每一个活着的人都用一粒干米来代表,那这些米可以填满一个边长 6.1 米、<a href="#footnote2-1-3475">1</a>也就是大约 20 英尺的立方体箱子——差不多是一栋两层小楼的大小。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Rice.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Rice"></a></p><p>那是相当多的米粒。</p><p>那 73 亿粒沙子呢?根据这张<a href="https://upload.wikimedia.org/wikipedia/commons/e/e2/Wentworth-Grain-Size-Chart.pdf" target="_blank" rel="noreferrer">有趣的图表</a>,&quot;沙子&quot;这个词可以指很多东西。73 亿粒&quot;非常粗&quot;的沙粒(直径约 2 毫米)可以填满一个高 4 米(13 英尺)的大型立方体房间。73 亿粒中等大小的沙粒(直径 0.25 毫米)则可以填满一个高 46 厘米(1.5 英尺)的中型纸箱。而 73 亿粒最细的、直径 0.0625 毫米的沙粒(再小就不算沙了——那叫粉砂)大约占 1,700 立方厘米的空间,差不多能装满一瓶 2 升的可乐,但还差一点点。</p><p>另外,走 73 亿步你可以绕地球……150 圈。(按每秒两步算,你得走 115 年。)(我又开始在文章里搞那种发散的数学螺旋计算了,然后把算出来的东西直接塞进正文。我尽量在这里不跑题吧,但这不容易。我们继续。)</p><p><strong>73 亿人的一维排列</strong></p><p>今天的第一个活动是把所有人排成一列。我们从厄瓜多尔的基多附近开始,就在赤道上,这条队伍将沿着赤道延伸。我们从卡洛斯开始。站这儿,卡洛斯。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Carlos.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Carlos"></a></p><p>排在第二个的是丹妮拉。第三个是你,安德烈娅。<a href="#footnote-1-3475">1</a> 既然我们要讲效率,我希望每个人都尽可能贴近前后的人,但不要真的碰到。有些人占的空间比别人多或少一点,因为大家体型不同,但我们就假设每加一个人,队伍平均加长一英尺(约 30 厘米)。<a href="#footnote-2-3475">2</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Carlos-and-Others.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Carlos and Others"></a></p><p>我们就这样一直排下去,队伍越来越长。为了让赤道上这条线保持笔直,我们跨海建桥、穿山打隧道。最终,这条线绕地球一圈,回到了卡洛斯脚下。但我们只用掉了 1.31 亿人——还不到人类总数的 2%——所以还得再绕一圈。再一圈。终于,在第 56 圈绕到一半的时候,在印度尼西亚的苏门答腊岛上,我们排到了最后一个人,大功告成。</p><p>好吧这让我有点烦躁,因为最后排出来的形状是个弹簧,不是一条线。我们换一种方式试试。</p><p>卡洛斯,再站回那个 X 上。我们让丹妮拉站到你肩膀上,然后安德烈娅站到她肩膀上,就这么一路往上垒。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Tower.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Tower"></a></p><p>一个人的平均身高是 165 厘米 (5&#39;5&quot;),但其中大约 30 厘米是从肩膀到头顶的距离,所以每往最上面那个人的肩膀上再加一个人,塔的高度平均只增加约 134 厘米 (4&#39;5&quot;)。</p><p>我们一层层往上垒,最终垒到了月球。糟糕的是,这时我们才用了 2.86 亿人,还剩 96% 的人类没上去。等我们终于垒完时,这座塔已经有 980 万公里 (610 万英里) 高,大约相当于到火星距离的 1/5、到金星距离的 1/4、到太阳距离的 1/15。<a href="#footnote2-2-3475">2</a></p><p>那如果我们大家手拉手围成一个大圈呢?假设我们肩并肩、手拉着手站着,这样每个人在圆周上大约占 3 英尺 (91 厘米) 的位置。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/3-Feet.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="3 Feet"></a></p><p>照这样围下去,我们最终这个圆的周长有 660 万公里 (410 万英里),直径 210 万公里 (130 万英里)。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Circle.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Circle"></a></p><p>当我们所有人都在外太空手拉手、因为没穿宇航服而瞬间毙命的时候,地球从我们的视角看过去大小,大概就跟平时夜空中的月亮差不多。</p><p>好吧,一维形状对大家来说都挺不方便的——我们收一收,试试二维:</p><p><strong>73 亿人的二维排列</strong></p><p>给人类形状加上第二个维度,整个物种一下子显得小多了。</p><p>把人类排成二维图形时,首先要问的问题是:「在不把大家挤死的前提下尽可能紧密地聚在一起,每个人需要占多少地面面积?」这篇文章里的答案是 0.1 平方米,也就是每平方米 10 个人。</p><p><strong>一平方米能舒舒服服地塞下多少人?</strong></p><p>为了寻找答案,我一头扎进了互联网最偏僻的角落,在那里遇到了两组闲得发慌的人。<a href="http://www.macleans.ca/general/how-many-journalists-can-you-fit-into-one-square-metre/" target="_blank" rel="noreferrer">第一组</a>展示了九位加拿大记者,他们选择花时间把自己挤进一平方米里。这样每人平均能得到一块 33cm x 33cm (13″ x 13″) 的方块站立。你可以在视频里看到,虽然确实挤,但没人被迫骚扰谁,而且所有人都能呼吸。</p><p>不过那用的全是成年人。全世界的<a href="http://world.bymap.org/MedianAge.html" target="_blank" rel="noreferrer">年龄中位数</a>是 29 岁,而最年幼的那 10 亿人身材往往相当小。<a href="https://kelvinroadschool.blogspot.com/2011/06/how-many-children-fit-into-square-metre.html" target="_blank" rel="noreferrer">第二个案例</a>把我们带到了世界另一头一所新西兰的普通小学,一位老师突发奇想,要看看她能往一平方米里塞进多少孩子。她最终塞进了惊人的 <strong>22</strong> 个孩子。</p><p>把这两场表演综合一下,似乎可以合理地说:每平方米 10 人是我们可以采用的一个安全的&quot;人口塞挤&quot;估算标准。9 个成年人站在方块里都没问题,再加进一些孩子应该能轻松把总数从 9 增加到 10(没错,有些成年人比平均值大得多,但也有些很瘦小——全世界<a href="http://www.biomedcentral.com/content/pdf/1471-2458-12-439.pdf" target="_blank" rel="noreferrer">成年人的平均体重</a>不过是 62kg (137lb),并不算大)。</p><p>按每平方米 10 人算,我们可以把 1,000 人塞进一个 10m x 10m 的方块里。一个篮球场是 28m x 15m,也就是说我们能在上面塞下 4,200 人,而且都在界内。</p><p>一个美式橄榄球场能容纳 54,000 人,足以装下列支敦士登或摩纳哥的全部人口;如果把场地扩大到足球场的大小——抱歉,是<em>足球 pitch</em>——我们能容纳超过 71,000 人,装下格陵兰的全部人口绰绰有余。</p><p>天安门广场相当大——880m x 500m,略小于半平方公里。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/china-tiananmen-square-aerial.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="china-tiananmen-square-aerial"></a></p><p>图片来源:<a href="http://keithrhiggons.com/tiananmen-square/" target="_blank" rel="noreferrer">Keith Higgons</a></p><p>如果它是空的,能装下 440 万人,也就是克罗地亚、阿曼、黎巴嫩、巴拿马、摩尔多瓦、乌拉圭、科威特、蒙古或立陶宛的全部人口。</p><p>一整平方公里能装下 1,000 万人——一座超大城市的人口——而你可以把全部 2,600 万斯堪的纳维亚人——挪威、瑞典、芬兰和丹麦的所有人<a href="#footnote2-3-3475">3</a>——塞进一平方英里里。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/scandinavia.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="scandinavia"></a></p><p>中央公园 (Central Park) 面积 3.41 平方公里 (1.3 平方英里),可以轻松容纳澳大利亚、摩洛哥、沙特阿拉伯、秘鲁、委内瑞拉、马来西亚、尼泊尔、莫桑比克或叙利亚的全部人口。你可以把全世界 1390 万犹太人塞进中央公园,里面还剩下装罗马尼亚、智利或荷兰全国人口的地方。公元前 5000 年整个人类——历史学家估计在 500 万到 2000 万之间——最多也就填满中央公园的一半多一点。</p><p>好戏才刚开场,坐稳了。</p><p>你可以把全部 3.2 亿美国人挤进一个 5.7 公里 × 5.7 公里 (3.5 英里 × 3.5 英里) 的正方形里,绕它走一圈用不了 5 小时。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Americans.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Americans"></a></p><p>而一个 10 公里 × 10 公里 (6.2 英里 × 6.2 英里) 的正方形——差不多是百慕大两倍大的一个小岛——可以装下<strong>十亿人</strong>(绕着走一圈大概 8 小时)。稍大一点的玛莎葡萄园岛 (Martha&#39;s Vineyard) 面积 226 平方公里,可以把全世界的基督徒都装进去〔冷笑话请自行脑补〕。或者呢,玛莎葡萄园岛也能装下北美洲和南美洲的全部人口……<strong>外加整个非洲的人口</strong>。至于全世界的女性,如果她们哪天受够了男人想成立个俱乐部,她们完全可以在 360 平方公里的加沙地带开全员大会。</p><p>好啦,我们真正想知道的是,要装下<strong>所有人</strong>——全部 73 亿人——需要多大一块地。答案是,一个 27 公里 × 27 公里 (16.8 英里 × 16.8 英里) 的正方形。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/All-Humans.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="All Humans"></a></p><p>这个正方形比巴林还小。放到非洲上面看,是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Africa.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Africa"></a></p><p>这个正方形也比纽约市小。</p><p>纽约市面积 786 平方公里,合 303 平方英里,整个人类都能塞进去——还剩下装另外 5 亿人的地方。具体来说:</p><ul><li>曼哈顿可以装下 5.9 亿人</li><li>布鲁克林可以装下 13.8 亿人</li><li>皇后区可以装下 28.3 亿人</li><li>布朗克斯可以装下 10.9 亿人</li><li>史泰登岛可以装下 15.1 亿人</li></ul><p>那来试试吧。先按地理区域分:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/NYC1.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="NYC1"></a></p><p>下面各位还好吗?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Crowd.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Crowd"></a></p><p>很好。现在,咱们挪一挪,按宗教重新排列:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/NYC2.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="NYC2"></a></p><p>这就是人类在地面上占据的面积——但这只算了活着的人。</p><p>科学家对<strong>有史以来所有存在过的人类</strong>总数的估算<a href="#footnote2-4-3475">4</a>通常在 900 亿到 1100 亿之间。最常见的估算是总共约 1080 亿人。基于这个假设,目前活着的人略少于所有存在过的人的 7%:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/108B.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="108B"></a></p><p>我们最近在餐桌栏目<a href="https://waitbutwhy.com/table/bring-one-person-back-from-the-dead" target="_blank" rel="noreferrer">讨论</a>过想让哪个死去的人复活——但如果我们把<em>所有</em>死去的人都复活了会怎样?我们需要多大的空间才能容纳他们?</p><p>我们需要 10800 平方公里——一个边长 103 公里(65 英里)的正方形——这轻松可以塞进牙买加、卡塔尔、科威特、冈比亚,或者康涅狄格州。</p><p>继续进入假想世界,我们可以把<strong>一万亿</strong>人塞进韩国、冰岛、危地马拉或古巴,如果我们用人填满地球陆地的每一平方米,那就能装下 1.48 千万亿人——是当前世界人口的 20 万倍。为了把这事做绝,让我们用人覆盖<strong>整个</strong>地球表面——包括海洋——这样一个地球大小的行星能容纳的总人数就略超过 5 千万亿人。<a href="#footnote-3-3475">3</a></p><p>这挺好的,但我爷爷们当年在二战里出生入死,可不是为了让我写关于二维事物的博客。是时候和大块头们过过招了。</p><p><strong>73 亿人的三维排列</strong></p><p>继续沿用每平方米地板 10 人的标准,我们把高度纳入方程,用全球人类平均身高 165 厘米(65 英寸)。<a href="#footnote-4-3475">4</a>所以我们可以造一个底面积 1 平方米、高 1.65 米的隔间,能塞进 10 个普通人。这就给了我们三维标准——每人 0.165 立方米,或每立方米 6.06 人。</p><p>当我们把大量人塞进三维建筑时,我们会通过建造不同高度的「楼层」来实现——有些楼层为高个子的人建得比 1.65 米高,有些为矮个子的人建得比平均值矮,但每个人所在的楼层,天花板都刚好在他头顶上方几毫米处,而所有楼层平均下来每层 1.65 米高。</p><p>帝国大厦的<a href="http://www.esbnyc.com/sites/default/files/esb_fact_sheet_4_9_14_4.pdf" target="_blank" rel="noreferrer">体积</a>为 105 万立方米,如果掏空并换上我们的新「楼层」,能容纳 630 万非常不开心的人。</p><p><a href="https://www.google.com/search?q=at%26t+stadium&amp;espv=2&amp;biw=1340&amp;bih=745&amp;site=webhp&amp;source=lnms&amp;tbm=isch&amp;sa=X&amp;ei=FxP1VNm7OabasATRvIGYDQ&amp;ved=0CAcQ_AUoAg#imgdii=_&amp;imgrc=_LI64REmZJ6y6M%253A%3B3jcWPn0ROouOkM%3Bhttp%253A%252F%252Fktul.images.worldnow.com%252Fimages%252F22937208_BG1.jpg%3Bhttp%253A%252F%252Fwww.ktul.com%252Fstory%252F22937208%252Fatt-buys-naming-rights-to-cowboys-stadium%3B1280%3B720" target="_blank" rel="noreferrer">AT&amp;T 体育场 (AT&amp;T Stadium)</a>,达拉斯牛仔队 (Dallas Cowboys) 的主场,是一座巨大的穹顶建筑,<a href="http://twistedsifter.com/2009/09/new-dallas-cowboys-stadium/" target="_blank" rel="noreferrer">容积</a>达 294 万立方米。如果加装楼层,它可以容纳 1760 万人。这个数字足以装下达拉斯的全部人口……再加上纽约、洛杉矶、芝加哥、旧金山和波士顿的全部人口。</p><p>按容积计算,世界上最大的建筑是位于华盛顿州的<a href="https://en.wikipedia.org/wiki/Boeing_Everett_Factory" target="_blank" rel="noreferrer">波音埃弗雷特工厂 (Boeing Everett Factory)</a>。它有 900 米 x 495 米的地基(尺寸几乎和天安门广场完全一致),天花板高度超过 33 米,总容积达 1330 万立方米——我们可以把全世界的法国人都塞进去,还能有富余空间再装下所有比利时人(总容量 7870 万人)。</p><p>但如果要把<em>所有人</em>都装进一座建筑里,现有地球上的任何建筑都不够用——我们得自己动手建。</p><p>按每人 0.165 立方米计算,我们需要略多于 12 亿立方米,也就是刚过 1 立方千米(精确地说是 1.204 立方千米)。<a href="#footnote-5-3475">5</a> 这座立方体建筑的边长为 1.07 千米(约三分之二英里),地基面积约 1.1 平方千米——大约是波音工厂地基的两倍多一点——高度为 1070 米(3511 英尺),比世界最高摩天大楼<a href="https://upload.wikimedia.org/wikipedia/en/9/93/Burj_Khalifa.jpg" target="_blank" rel="noreferrer">哈利法塔 (Burj Khalifa)</a> 还要高 29%。这是一座<em>很大</em>的建筑,但无论是地基还是高度,单独来看,以现代建筑标准都不是无法想象的。如果我们把它建在曼哈顿,大概长这样(加了其他建筑作为参照):</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Cube1.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Cube1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Cube2.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Cube2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/Cube3.jpg" target="_blank" rel="noreferrer"><img src="'+C+'" alt="Cube3"></a></p><p>那栋楼里的某处有你。别的某处有你所有的朋友。那里面某处有一个 16 岁的柬埔寨女孩和她所有的朋友。某处有一个索马里海盗,他的理发师,还有他理发师的所有朋友。所有 NBA 球员都在里面,连同每一个摇滚明星、电影明星、超模、政客。每一位酒保、建筑工人、神父、律师、囚犯、公主、士兵和牙医都在那栋楼里的某处,连同全部 14 亿中国人、每一个金发的人,以及 ISIS 的每一名成员。</p><p>人类这个物种,在一个维度上——绕地球 55 圈,或围成一个让月球轨道相形见绌的圆环——看起来铺天盖地地庞大,但当它能装进巴林或纽约市里还绰绰有余时,就显得好管理多了,而当它被整整齐齐地组织成一个你只要慢跑 20 分钟就能绕一圈的立方体时,甚至有种小巧可爱的感觉。</p><p>这样一来,我们最初的目标就完成了。可是,如果我们不在这里结束这篇文章,而是再往前走一步呢?费了这么大劲,现在我们所有原子里都还有那么多空荡荡的空间,谁愿意停下来?</p><p><strong>73 亿人类压缩到他们的原子核</strong></p><p>每个原子都不一样,但一个大致的经验规则是:一个原子的直径大约是其原子核直径的 10 万倍,而原子核几乎承载了原子的全部质量。换算到三维里,这意味着一个原子的原子核只占原子总体积的大约一<em>千万亿</em>分之一。我想象这件事的方式是把一个原子想成一立方公里——一个比最高摩天大楼还要高的空心立方体(差不多就是我们上面那个人类立方体的大小)。这栋楼大到,如果你在里面,吊在天花板上,然后松手,你要自由落体大约 15 秒才会砸到地面。如果你站在底部一边,你得走大约 12 分钟才能走到另一边。</p><p>如果那个巨大的立方体是一个原子,那么在它中间某处有一个 1 立方厘米的<em>方糖</em>——那就是原子核。而原子的质量差不多正好等于那块方糖的质量,而它只占据了千万亿分之一的空间。原子里其余的 999,999,999,999,999 千万亿分之几乎全部都是没有质量的空荡荡的空间。</p><p>你身体的质量,就是你身体里每一个原子中间那些方糖加起来的质量。</p><p>那么人类这个物种<em>真正</em>有多大呢?当我们把 73 亿人所有原子里的空白空间都去掉,剩下的是什么?</p><p>一颗 M&amp;M 巧克力豆。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/03/MM1.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="M&amp;M"></a></p><p>其实还不够。一个人的体积大约是 0.0664 立方米,所以全人类的总体积大约是 4.85 亿立方米。把它缩小到千万亿分之一,得到 0.485 立方厘米。一颗 M&amp;M 巧克力豆是 0.636 立方厘米,大了约 30%。彩虹糖也太大 (0.74 立方厘米),25 美分硬币 (0.809 立方厘米) 和 5 美分硬币 (0.689 立方厘米) 也是。要找到日常生活中小到 0.485 立方厘米的物件其实挺难的 (美国 1 美分硬币倒是可以,但它 0.433 立方厘米,稍微差一点才能把我们都装进去)。</p><p>今天就到这里吧。想象一颗 4.5 亿吨重的 M&amp;M 巧克力豆——比 75 座吉萨金字塔还重——只要有人把我们捏得够紧,我们所有人都能塞进去。</p><hr><p><strong>如果你喜欢这篇文章,这里还有另外四篇「无意义计算 (Pointless Calculations)」类别的文章:</strong></p><p><a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">241 万亿美元能买什么?</a> 又是立方体。这次是金子做的。</p><p><a href="https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html" target="_blank" rel="noreferrer">一千万亿颗酸酸小人糖长什么样?</a> 太空中的糖果立方体。</p><p><a href="https://waitbutwhy.com/2013/09/putting-all-worlds-water-into-big-cube.html" target="_blank" rel="noreferrer">把世界上所有的海洋、湖泊和河流装进立方体。</a> 水立方。</p><p><a href="https://waitbutwhy.com/2013/08/what-if-all-71-billion-people-moved-to.html" target="_blank" rel="noreferrer">如果全世界 71 亿人都搬到突尼斯去?</a> 这篇没有立方体,但也是拿人类总人口做的实验 (对火柴人比较仁慈)。</p><hr><p>如果你喜欢 Wait But Why,请注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一出来就会发送给你。</p><p>想支持 Wait But Why,可以访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>根据这份可能还算靠谱的<a href="http://www.studentsoftheworld.info/penpals/stats.php3?Pays=ECU" target="_blank" rel="noreferrer">厄瓜多尔热门名字列表</a>,Carlos、Daniela 和 Andrea 现在正当红。<a href="#note-1-3475">↩</a></p></li><li><p>公制/非公制这事儿真是烦得让人难以置信。差不多一半的 WBW 读者来自公制国家,所以我不能只用英制单位;但美国读者又占了一半多一点,所以我也不能只用公制,因为对他们来说英尺和英里更直观。所以我只好两套单位都写,大家都嫌烦——就因为美国决定坚持使用一套完全没道理的计量系统。<a href="#note-2-3475">↩</a></p></li><li><p>没啥用的信息。<a href="#note-3-3475">↩</a></p></li><li><p>上一节结尾把气氛烘托得那么足,这一节居然用这么平淡的一句话开场,超级尴尬。<a href="#note-4-3475">↩</a></p></li><li><p>顺便算了一下,要装下<em>有史以来</em>活过的所有 1080 亿人,我们需要一栋边长 2.6 公里的立方体建筑。<a href="#note-5-3475">↩</a></p></li></ol><hr><ol><li><p>一杯米大约有 7000 粒,也就是 240 毫升里有 7000 粒,换算下来 73 亿粒米可以填满 251 立方米。(本文中,灰色方形脚注用于计算和其他技术细节。蓝色圆形则是些无关的想法和冷知识。)<a href="#note2-1-3475">↩</a></p></li><li><p>在离地球最近的时候,火星距我们 3390 万英里,金星距我们 2400 万英里,太阳距我们 9300 万英里。<a href="#note2-2-3475">↩</a></p></li><li><p>斯堪的纳维亚 (Scandinavia) 的定义有点让人迷糊。有些人不算丹麦或芬兰,有些人则把冰岛也算进来。最常见的定义似乎就是这四个国家。<a href="#note2-3-3475">↩</a></p></li><li><p>以公元前 50000 年作为人类的起点。<a href="#note2-4-3475">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html&amp;description=7.3%20Billion%20People,%20One%20Building" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p>',109)])])}const N=t(A,[["render",q]]);export{O as __pageData,N as default};
